SELECT COUNT(DISTINCT PT.PK) AS TOTAL FROM LATTES_P_PRODTEC LPP JOIN SERVIDOR S ON S.PK_SIAPE = LPP.FK_SIAPE JOIN LATTES_PRODTEC PT ON PT.PK = LPP.FK_PRODTEC WHERE LOWER(PT.NATUREZA) = LOWER('assessoria') AND PT.ANO = 2023 AND LOWER(S.GENERO) = LOWER('feminino') AND LOWER(S.SIGLA_CAMPUS) = LOWER('gyn') AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%letras%')